public class PassByValue {
    // Primitives: cannot change caller's variable
    static void tryDouble(int x) {
        x = x * 2;  // only modifies local copy
    }

    // Objects: CAN modify object state, CANNOT reassign reference
    static void addElement(java.util.List<Integer> list) {
        list.add(99);          // modifies the object itself — caller sees this
    }
    static void tryReassign(java.util.List<Integer> list) {
        list = new java.util.ArrayList<>();  // only changes local reference
        list.add(999);          // caller's list is unaffected
    }

    public static void main(String[] args) {
        // Primitive test
        int a = 5;
        tryDouble(a);
        System.out.println(a);  // 5 — unchanged

        // Object state mutation
        java.util.List<Integer> nums = new java.util.ArrayList<>();
        nums.add(1); nums.add(2);
        addElement(nums);
        System.out.println(nums);  // [1, 2, 99] — 99 was added

        // Reference reassignment
        tryReassign(nums);
        System.out.println(nums);  // [1, 2, 99] — still unchanged

        // int vs Integer (autoboxing pitfall)
        Integer box = 5;
        tryDouble(box);            // unboxed to int, then doubled locally
        System.out.println(box);  // 5 — Integer is immutable
    }
}

public class OverloadingDemo {
    // Overloaded: same name, different parameter lists
    static void print(int n)     { System.out.println("int: " + n); }
    static void print(double d)  { System.out.println("double: " + d); }
    static void print(String s)  { System.out.println("String: " + s); }
    static void print(int a, int b) { System.out.println("two ints: " + a + ", " + b); }
    static void print(Object o)  { System.out.println("Object: " + o); }

    // Varargs — variable number of arguments
    static int sum(int... nums) {
        int total = 0;
        for (int n : nums) total += n;  // varargs treated as int[]
        return total;
    }

    // Overload resolution pitfall
    public static void main(String[] args) {
        print(42);          // calls print(int)
        print(3.14);        // calls print(double)
        print("hello");     // calls print(String)
        print(1, 2);        // calls print(int, int)
        print(null);        // AMBIGUOUS! print(String) or print(Object)?
        // Java chooses the most specific: print(String)

        System.out.println(sum());          // 0
        System.out.println(sum(1, 2, 3));   // 6
        System.out.println(sum(1, 2, 3, 4, 5)); // 15

        // Widening: byte→short→int→long→float→double
        byte b = 10;
        print(b);  // calls print(int) — widened, not print(Object)
    }
}

