public class TowerOfHanoi {
    static int moves = 0;

    static void hanoi(int n, char from, char to, char aux) {
        if (n == 0) return;         // base case
        hanoi(n - 1, from, aux, to); // move n-1 disks to aux
        moves++;
        System.out.printf("Move disk %d: %c → %c%n", n, from, to);
        hanoi(n - 1, aux, to, from); // move n-1 disks from aux to to
    }

    public static void main(String[] args) {
        hanoi(3, 'A', 'C', 'B');
        System.out.println("Total moves: " + moves); // 2^n - 1 = 7
    }
    // Call tree for n=3:
    // hanoi(3,A,C,B)
    //   hanoi(2,A,B,C)
    //     hanoi(1,A,C,B) → Move disk 1: A→C
    //     Move disk 2: A→B
    //     hanoi(1,C,B,A) → Move disk 1: C→B
    //   Move disk 3: A→C
    //   hanoi(2,B,C,A)
    //     hanoi(1,B,A,C) → Move disk 1: B→A
    //     Move disk 2: B→C
    //     hanoi(1,A,C,B) → Move disk 1: A→C
}

import java.util.*;

public class FibMemo {
    // Naive recursion: O(2^n) — exponential
    static long fibNaive(int n) {
        if (n <= 1) return n;
        return fibNaive(n - 1) + fibNaive(n - 2);
    }

    // Top-down memoization: O(n)
    static Map<Integer, Long> memo = new HashMap<>();
    static long fibMemo(int n) {
        if (n <= 1) return n;
        if (memo.containsKey(n)) return memo.get(n);  // cache hit
        long result = fibMemo(n - 1) + fibMemo(n - 2);
        memo.put(n, result);                          // cache miss → compute and store
        return result;
    }

    // Bottom-up iterative: O(n) time, O(1) space
    static long fibDP(int n) {
        if (n <= 1) return n;
        long prev2 = 0, prev1 = 1;
        for (int i = 2; i <= n; i++) {
            long curr = prev1 + prev2;
            prev2 = prev1;
            prev1 = curr;
        }
        return prev1;
    }

    public static void main(String[] args) {
        System.out.println(fibNaive(10)); // 55 (fast for small n)
        System.out.println(fibMemo(50));  // 12586269025 (fast)
        System.out.println(fibDP(50));    // 12586269025 (fast, no extra space)
        // fibNaive(50) would take ~hours
    }
}

public class StackFrameViz {
    static int factorial(int n) {
        System.out.println("Enter factorial(" + n + ")");
        if (n <= 1) {
            System.out.println("Base case: factorial(1) = 1");
            return 1;
        }
        int result = n * factorial(n - 1);
        System.out.println("Return factorial(" + n + ") = " + result);
        return result;
    }

    // Iterative alternative — avoids StackOverflowError for large n
    static long factorialIterative(int n) {
        long result = 1;
        for (int i = 2; i <= n; i++) result *= i;
        return result;
    }

    public static void main(String[] args) {
        System.out.println("=== Recursive ===");
        System.out.println(factorial(4));
        System.out.println("\n=== Iterative ===");
        System.out.println(factorialIterative(20));  // 2432902008176640000

        // StackOverflowError demo (commented out — would crash)
        // factorial(100000);  // Default JVM stack ~512KB, each frame ~100 bytes
        // JVM option: -Xss4m to increase stack size
    }
}

