public class Solution {
    public double myPow(double x, int n) {
        long N = n;  // use long to handle Integer.MIN_VALUE
        if (N < 0) { x = 1 / x; N = -N; }
        return fastPow(x, N);
    }

    private double fastPow(double x, long n) {
        if (n == 0) return 1.0;
        if (n % 2 == 0) return fastPow(x * x, n / 2);
        return x * fastPow(x, n - 1);
    }
}

