        return dp(n, memo);
    }

    private int dp(int n, int[] memo) {
        if (n <= 1) return 1;
        if (memo[n] != 0) return memo[n];
        memo[n] = dp(n - 1, memo) + dp(n - 2, memo);
        return memo[n];
    }
}

