public class Solution {
    public boolean solveMaze(int[][] maze) {
        return solve(maze, 0, 0);
    }

    private boolean solve(int[][] maze, int r, int c) {
        int m = maze.length, n = maze[0].length;
        if (r < 0 || r >= m || c < 0 || c >= n) return false;
        if (maze[r][c] != 0) return false;  // wall or visited
        if (r == m - 1 && c == n - 1) { maze[r][c] = 2; return true; }  // reached exit
        maze[r][c] = 2;  // mark as path
        if (solve(maze, r+1, c) || solve(maze, r-1, c) ||
            solve(maze, r, c+1) || solve(maze, r, c-1)) return true;
        maze[r][c] = 0;  // backtrack: unmark
        return false;
    }
}

