import java.util.function.*;
public class Solution {
    public Function<Integer,Integer> compose(
        Function<Integer,Integer> f,
        Function<Integer,Integer> g) {
        return x -> f.apply(g.apply(x));
    }

    public int applyN(Function<Integer,Integer> f, int n, int x) {
        if (n == 0) return x;
        return applyN(f, n - 1, f.apply(x));
    }

    public static void main(String[] args) {
        Solution sol = new Solution();
        Function<Integer,Integer> doubleIt = x -> x * 2;
        Function<Integer,Integer> addOne   = x -> x + 1;
        Function<Integer,Integer> doubleThenAdd = sol.compose(addOne, doubleIt);
        System.out.println(doubleThenAdd.apply(5));  // addOne(doubleIt(5)) = 11
        System.out.println(sol.applyN(doubleIt, 3, 1));  // 1→2→4→8
    }
}

