public class Solution {
    private int pos;
    private String expr;

    public boolean parseBoolExpr(String expression) {
        this.expr = expression;
        this.pos = 0;
        return parse();
    }

    private boolean parse() {
        char c = expr.charAt(pos++);
        if (c == 't') return true;
        if (c == 'f') return false;
        if (c == '!') {
            pos++;  // consume '('
            boolean val = !parse();
            pos++;  // consume ')'
            return val;
        }
        // c is '&' or '|'
        pos++;  // consume '('
        boolean result = (c == '&');
        while (true) {
            boolean sub = parse();
            result = (c == '&') ? result && sub : result || sub;
            if (expr.charAt(pos) == ')') break;
            pos++;  // consume ','
        }
        pos++;  // consume ')'
        return result;
    }
}
